 * for the session details webview. Only text messages and agent-originated tool-use
 * activity are retained; tool results and unknown/raw events are skipped.
 *
 * @param content Raw transcript content from `full.jsonl` or similar sources.
 * @returns Conversation turns in source order with inline tool activity summaries.
 */
export function buildTranscriptTurns(content: string): NormalizedTranscriptTurn[] {
	const events = parseTranscript(content);
	const turns: NormalizedTranscriptTurn[] = [];
	let currentAgentTurn: NormalizedTranscriptTurn | undefined;
	let currentAgentMessageId: string | undefined;
	let pendingToolActivities: NormalizedTranscriptToolActivity[] = [];

	for (const event of events) {
		const record = isJsonObject(event.raw) ? event.raw : undefined;
		const actor = classifyRenderableActor(record, event.eventType);
		if (!actor) {
			continue;
		}

		const text = extractTurnText(event.raw, actor);
		const toolActivities = actor === "agent"
			? dedupeToolActivities(extractToolActivities(event.raw).filter((activity) => activity.kind === "tool_use"))
