/**
 * Resolves the detail payload used by the session details webview panel.
 *
 * Live sessions prefer their current transcript file when available, while
 * checkpoint-backed sessions resolve the latest checkpoint snapshot for the
 * selected `sessionId`.
 *
 * @param repoPath Repository root used to load session and transcript state.
 * @param target Session selection context from the Sessions tree.
 * @returns Structured session detail content ready for webview rendering.
 */
export async function getSessionDetail(
	repoPath: string,
	target: SessionDetailTarget,
