		target.promptPreview,
	);
	const startedAt = extractTranscriptFirstTimestamp(transcript)
		?? checkpointSnapshot?.session.metadata.createdAt
		?? target.startedAt;
	const lastActivityAt = extractTranscriptLatestTimestamp(transcript)
		?? checkpointSnapshot?.session.metadata.createdAt
		?? target.lastActivityAt
		?? startedAt;
	const turns = buildSessionConversationTurns(buildTranscriptTurns(transcript ?? ""), target);

	return {
		sessionId: target.sessionId,
		source: target.source,
		promptPreview,
		status: target.status,
		startedAt,
		lastActivityAt,
		durationMs: resolveSessionDetailDuration(
