		),
		checkpointCount: target.checkpointCount,
		turnCount: target.turnCount
			?? checkpointSnapshot?.session.metadata.sessionMetrics?.turnCount
			?? turns.length,
		toolCount: target.toolCount ?? countRenderedToolUses(turns),
		tokenCount: target.tokenCount ?? totalTokenUsage(checkpointSnapshot?.session.metadata.tokenUsage),
		attribution: target.attribution ?? checkpointSnapshot?.session.metadata.initialAttribution,
		model: target.model ?? checkpointSnapshot?.session.metadata.model,
		transcriptAvailable: typeof transcript === "string" && transcript.trim().length > 0,
		turns,
	};
}

