function parseJsonMaybe(text: string): unknown {
	try {
		return JSON.parse(text) as unknown;
	} catch {
		return undefined;
	}
}

function* iterateTranscriptLinesFromStart(content: string): Generator<string> {
	let lineStart = 0;

	for (let index = 0; index < content.length; index += 1) {
		const char = content[index];
		if (char !== "\n" && char !== "\r") {
			continue;
		}

		const line = content.slice(lineStart, index).trim();
		if (line.length > 0) {
			yield line;
		}

		if (char === "\r" && content[index + 1] === "\n") {
			index += 1;
		}
		lineStart = index + 1;
	}

	const lastLine = content.slice(lineStart).trim();
	if (lastLine.length > 0) {
		yield lastLine;
	}
}

function* iterateTranscriptLinesFromEnd(content: string): Generator<string> {
	let lineEnd = content.length;

	for (let index = content.length - 1; index >= 0; index -= 1) {
		const char = content[index];
		if (char !== "\n" && char !== "\r") {
			continue;
		}

		const line = content.slice(index + 1, lineEnd).trim();
		if (line.length > 0) {
			yield line;
		}
		lineEnd = index;
	}

	const firstLine = content.slice(0, lineEnd).trim();
	if (firstLine.length > 0) {
		yield firstLine;
	}
}

function sortTranscriptChunkNames(entryNames: string[]): string[] {
	return [...entryNames].sort((left, right) => {
		const leftIndex = getTranscriptChunkIndex(left) ?? Number.MAX_SAFE_INTEGER;
		const rightIndex = getTranscriptChunkIndex(right) ?? Number.MAX_SAFE_INTEGER;
		if (leftIndex !== rightIndex) {
			return leftIndex - rightIndex;
		}

		return left.localeCompare(right);
	});
}

function getTranscriptChunkIndex(entryName: string): number | undefined {
	const match = entryName.match(/^full\.jsonl\.(\d+)$/);
	if (!match) {
		return undefined;
	}

	const parsed = Number(match[1]);
	return Number.isInteger(parsed) && parsed > 0 ? parsed : undefined;
}

function toTranscriptEvent(index: number, value: unknown, rawText: string): TranscriptEvent {
	if (isJsonObject(value)) {
		return {
			index,
			eventType: readFirstString(value, ["type", "event_type", "eventType", "kind"]),
			timestamp: readFirstString(value, ["timestamp", "ts", "created_at"]),
			raw: value,
			rawText,
		};
	}

	return {
		index,
		raw: value,
		rawText,
	};
}

function classifyRenderableActor(
	record: Record<string, unknown> | undefined,
	eventType: string | undefined,
): "user" | "agent" | undefined {
	if (!record && !eventType) {
		return undefined;
	}

	const recordType = normalizeString(record ? readString(record, "type") : undefined) ?? normalizeString(eventType);
	const role = record
		? normalizeString(readString(record.message, "role") ?? readString(record, "role"))
		: undefined;

	if (role === "assistant" || recordType === "assistant") {
		return "agent";
	}

	if (role === "user" || isUserEventType(recordType)) {
		return "user";
	}

	return recordType === "message" ? "agent" : undefined;
}

function buildTurnId(record: Record<string, unknown> | undefined, index: number): string {
	return (record ? readString(record, "uuid") : undefined) ?? `turn-${index}`;
}

function extractAssistantMessageId(record: Record<string, unknown> | undefined): string | undefined {
	if (!record) {
		return undefined;
	}

	return readString(record.message, "id");
}

function extractTurnText(value: unknown, eventTypeHint?: string): string | undefined {
	const segments = collectTextSegments(value, normalizeString(eventTypeHint));
	if (segments.length === 0) {
		return undefined;
	}

	return dedupeSegments(segments).join("\n\n");
}

function collectTextSegments(value: unknown, roleHint?: string): string[] {
	if (typeof value === "string") {
		if (!roleHint) {
			return [];
		}

		const normalized = collapseWhitespace(value);
		return normalized.length > 0 ? [normalized] : [];
	}

	if (Array.isArray(value)) {
		return value.flatMap((entry) => collectTextSegments(entry, roleHint));
	}

	if (!isJsonObject(value)) {
		return [];
	}

	const typeValue = normalizeString(readString(value, "type") ?? readString(value, "kind"));
	if (typeValue === "tool_use" || typeValue === "tool_call" || typeValue === "tool_result") {
		return [];
	}

	const role = normalizeString(readString(value.info, "role") ?? readString(value, "role")) ?? roleHint;
	const segments: string[] = [];

	if ((typeValue === "text" || typeValue === "input_text") && typeof value.text === "string") {
		const normalized = collapseWhitespace(value.text);
		if (normalized.length > 0) {
			segments.push(normalized);
		}
		return segments;
	}

	if (typeof value.text === "string") {
		const normalized = collapseWhitespace(value.text);
		if (normalized.length > 0) {
			segments.push(normalized);
		}
	}

	if (typeof value.content === "string" && (role === "user" || role === "assistant" || roleHint !== undefined || typeValue === "message")) {
		const normalized = collapseWhitespace(value.content);
		if (normalized.length > 0) {
			segments.push(normalized);
		}
	}

	if (typeof value.message === "string") {
		const normalized = collapseWhitespace(value.message);
		if (normalized.length > 0) {
			segments.push(normalized);
		}
	}

	for (const key of ["message", "content", "parts", "items", "messages", "events", "data"]) {
		const nested = value[key];
		if (nested === undefined || typeof nested === "string") {
			continue;
		}
		segments.push(...collectTextSegments(nested, role));
	}

	return segments;
}

function dedupeSegments(values: string[]): string[] {
	const deduped: string[] = [];

	for (const value of values) {
		if (value.length === 0 || deduped[deduped.length - 1] === value) {
			continue;
		}
		deduped.push(value);
	}

	return deduped;
}

function extractToolActivities(value: unknown): NormalizedTranscriptToolActivity[] {
	if (Array.isArray(value)) {
		return value.flatMap((entry) => extractToolActivities(entry));
	}

	if (!isJsonObject(value)) {
		return [];
	}

	const directToolUse = buildToolUseActivity(value);
	if (directToolUse) {
		return [directToolUse];
	}

	return ["message", "content", "parts", "items", "messages", "events", "data", "tool_calls", "tool_call", "toolUseResult"]
		.flatMap((key) => extractToolActivities(value[key]));
}

function buildToolUseActivity(value: Record<string, unknown>): NormalizedTranscriptToolActivity | undefined {
	const typeValue = normalizeString(readString(value, "type") ?? readString(value, "kind"));
	const functionRecord = isJsonObject(value.function) ? value.function : undefined;
	if (typeValue !== "tool_use" && typeValue !== "tool_call" && typeof functionRecord?.name !== "string") {
		return undefined;
	}

	const toolName = readString(value, "name") ?? readString(functionRecord, "name") ?? "Tool";
	const toolUseId = readString(value, "id");
	return {
		id: `${toolUseId ?? toolName}-use`,
		kind: "tool_use",
		toolUseId,
		label: toolName,
		detail: truncateDetail(extractToolUseDetail(value, functionRecord)),
	};
}

function dedupeToolActivities(activities: NormalizedTranscriptToolActivity[]): NormalizedTranscriptToolActivity[] {
	const deduped: NormalizedTranscriptToolActivity[] = [];
	const seen = new Set<string>();

	for (const activity of activities) {
		const key = [
			activity.kind,
			activity.toolUseId ?? "",
			activity.label,
			activity.detail ?? "",
		].join("|");
		if (seen.has(key)) {
			continue;
		}
		seen.add(key);
		deduped.push(activity);
	}

	return deduped;
}

function extractToolUseDetail(
	value: Record<string, unknown>,
	functionRecord: Record<string, unknown> | undefined,
): string | undefined {
	const inputRecord = isJsonObject(value.input) ? value.input : undefined;
	const direct = readFirstString(
		inputRecord ?? functionRecord ?? value,
		["command", "path", "pattern", "query", "url", "description", "text", "prompt"],
	);
	if (direct) {
		return collapseWhitespace(direct);
	}

	const serialized = serializeUnknown(inputRecord ?? functionRecord?.arguments ?? value.arguments);
	return serialized ? collapseWhitespace(serialized) : undefined;
}

function serializeUnknown(value: unknown): string | undefined {
	if (value === undefined) {
		return undefined;
	}

	if (typeof value === "string") {
		return value;
	}

	try {
		return JSON.stringify(value);
	} catch {
		return undefined;
	}
}

function truncateDetail(value: string | undefined, maxLength = 180): string | undefined {
	if (!value) {
		return undefined;
	}

	return value.length <= maxLength ? value : `${value.slice(0, maxLength - 1)}…`;
}

function readFirstString(record: Record<string, unknown>, keys: string[]): string | undefined {
	for (const key of keys) {
		const value = record[key];
		if (typeof value === "string") {
			return value;
		}
	}

	return undefined;
}

function extractPromptText(value: unknown, eventTypeHint?: string): string | undefined {
	if (typeof value === "string" && isUserEventType(eventTypeHint)) {
		return value;
	}

	if (Array.isArray(value)) {
		for (const entry of value) {
			const extracted = extractPromptText(entry, eventTypeHint);
			if (extracted) {
				return extracted;
			}
		}
		return undefined;
	}

	if (!isJsonObject(value)) {
		return undefined;
	}

	const recordType = normalizeString(readString(value, "type") ?? readString(value, "kind") ?? eventTypeHint);
	const role = normalizeString(readString(value.info, "role") ?? readString(value, "role")) ?? recordType;

	if (recordType === "queue-operation") {
		const queuedPrompt = readFirstString(value, ["content", "message", "prompt", "text", "input"]);
		if (queuedPrompt) {
			return queuedPrompt;
		}
	}

	if (role === "user") {
		const direct = readFirstString(value, ["content", "message", "prompt", "text", "input"]);
		if (direct) {
			return direct;
		}

		for (const key of ["content", "parts", "items"]) {
			const extracted = extractPromptTextParts(value[key], "user");
			if (extracted) {
				return extracted;
			}
		}
	}

	const direct = isUserEventType(eventTypeHint) ? readFirstString(value, ["content", "message", "prompt", "text", "input"]) : undefined;
	if (direct) {
		return direct;
	}

	if (value.message !== undefined) {
		const extracted = extractPromptText(value.message, role ?? eventTypeHint);
		if (extracted) {
			return extracted;
		}
	}

	for (const key of ["messages", "events", "items", "parts", "content", "data"]) {
		const nested = value[key];
		if (nested !== undefined) {
			const extracted = extractPromptTextParts(nested, role ?? eventTypeHint);
			if (extracted) {
				return extracted;
			}
		}
	}

	for (const nested of Object.values(value)) {
		const extracted = extractPromptText(nested, role ?? eventTypeHint);
		if (extracted) {
			return extracted;
		}
	}

	return undefined;
}

function countPossibleToolUses(value: unknown): number {
	if (Array.isArray(value)) {
		return value.reduce((sum, entry) => sum + countPossibleToolUses(entry), 0);
	}

	if (!isJsonObject(value)) {
		return 0;
	}

	let count = 0;
	const typeValue = normalizeString(readString(value, "type") ?? readString(value, "kind"));
	if (typeValue === "tool_result") {
		return 0;
	}

	if (typeValue === "tool_use" || typeValue === "tool_call") {
		count += 1;
	}

	if (Array.isArray(value.tool_calls)) {
		count += value.tool_calls.filter((toolCall) => isToolCallRecord(toolCall)).length;
	}

	if (isToolCallRecord(value.tool_call)) {
		count += 1;
	}

	if (count === 0 && isToolCallRecord(value)) {
		count += 1;
	}

	for (const key of ["message", "content", "parts", "items", "messages", "events", "data"]) {
		const nested = value[key];
		if (nested !== undefined) {
			count += countPossibleToolUses(nested);
		}
	}

	return count;
}

function isUserEventType(value: string | undefined): boolean {
	if (!value) {
		return false;
	}

	return ["user", "human", "prompt", "input"].includes(value.toLowerCase());
}

