	const userInitials = buildInitials(target.author, "U");
	const agentInitials = buildInitials(target.agent, "AI");

	return turns.map((turn) => ({
		id: turn.id,
		actor: {
			kind: turn.actor,
			initials: turn.actor === "user" ? userInitials : agentInitials,
		},
		timestamp: turn.timestamp,
		text: turn.text,
		toolActivities: turn.toolActivities.map((activity) => ({
			id: activity.id,
			kind: activity.kind,
			label: activity.label,
			detail: activity.detail,
		})),
	}));
}

function buildInitials(value: string | undefined, fallback: string): string {
	if (!value) {
		return fallback;
	}

	const parts = value
		.trim()
		.split(/[^A-Za-z0-9]+/)
		.filter((part) => part.length > 0);
	if (parts.length === 0) {
		return fallback;
	}

	if (parts.length === 1) {
		return parts[0][0]?.toUpperCase() ?? fallback;
	}

	return parts
		.slice(0, 2)
		.map((part) => part[0]?.toUpperCase() ?? "")
		.join("");
}

function countRenderedToolUses(turns: SessionConversationTurn[]): number | undefined {
	const total = turns.reduce((count, turn) => count + turn.toolActivities.filter((activity) => activity.kind === "tool_use").length, 0);
	return total > 0 ? total : undefined;
}

