				if (!shouldShowLiveSessions(this.workspaceState) && !hasCheckpointSelection(this.selectedCheckpointSelection)) {
					this.debug(`queueRootLoad: no live sessions or checkpoint selection after gen=${generation}`);
					this.loadState = { kind: "loaded", cards: [] };
					return [];
				}

				const mode = shouldShowLiveSessions(this.workspaceState) ? "live" : "checkpoint";
				const timeout = new Promise<never>((_resolve, reject) => {
					setTimeout(() => reject(new Error("Session load timed out")), LOAD_TIMEOUT_MS);
				});
				const work = shouldShowLiveSessions(this.workspaceState)
					? this.loadLiveSessions(repoPath).then((cards) => cards.map(adaptLiveCard))
					: this.loadCheckpointSessions(repoPath, this.selectedCheckpointSelection?.checkpointIds ?? []).then((cards) => cards.map(adaptCheckpointSessionCard));
				const cards = await Promise.race([work, timeout]);
				const elapsed = Date.now() - startTime;
				if (this.loadGeneration !== generation) {
					this.debug(`queueRootLoad: stale gen=${generation} (current=${this.loadGeneration}), discarding ${cards.length} cards after ${elapsed}ms`);
					return this.currentCards();
				}

				const sortedCards = sortCards(cards);
				this.debug(`queueRootLoad: success, gen=${generation}, mode=${mode}, ${cards.length} cards in ${elapsed}ms`);
				this.loadState = { kind: "loaded", cards: sortedCards };
				return sortedCards;
			} catch (error) {
				const elapsed = Date.now() - startTime;
				if (this.loadGeneration !== generation) {
					this.debug(`queueRootLoad: stale gen=${generation} (current=${this.loadGeneration}), ignoring error after ${elapsed}ms: ${error}`);
					return this.currentCards();
				}

				const message = error instanceof Error ? error.message : "Failed to load sessions";
				this.debug(`queueRootLoad: error, gen=${generation}, ${elapsed}ms: ${message}`);
				this.loadState = { kind: "error", message };
				return [];
			} finally {
				if (this.pendingRootLoad === pendingLoad) {
					this.pendingRootLoad = undefined;
				}
				if (this.loadGeneration === generation) {
					this.changeEmitter.fire();
				}
			}
		})();

		this.pendingRootLoad = pendingLoad;
		return pendingLoad;
	}

	private currentCards(): SessionTreeCard[] {
		return this.loadState.kind === "loaded" ? this.loadState.cards : [];
	}

	private buildRootItems(): vscode.TreeItem[] {
		switch (this.loadState.kind) {
			case "error":
				return [
					new EmptyStateItem(this.loadState.message, "warning", "An error occurred while reading session data. Try refreshing."),
					buildRefreshAction(this.commands),
					buildShowStatusAction(this.commands),
				];
			case "loaded":
				if (this.loadState.cards.length > 0) {
					return this.loadState.cards.map((card) => new SessionsTreeItem(card));
				}
				if (hasCheckpointSelection(this.selectedCheckpointSelection)) {
					return [
						new EmptyStateItem(
							"No sessions in selected checkpoint",
							"history",
							"The selected checkpoint does not have any resolved sessions in the current repository context.",
						),
						buildRefreshAction(this.commands),
					];
				}
				return [
					new EmptyStateItem(
						"No sessions to show",
						"play-circle",
						"Live sessions appear here automatically. When none are running, select a checkpoint to inspect the sessions captured in it.",
					),
					buildRefreshAction(this.commands),
				];
			case "ready":
				return [
					new EmptyStateItem(
						"No sessions to show",
						"play-circle",
						"Live sessions appear here automatically. When none are running, select a checkpoint to inspect the sessions captured in it.",
					),
					buildRefreshAction(this.commands),
				];
		}
	}
}

export function getSessionSelectionContext(element: vscode.TreeItem | undefined): SessionDetailTarget | undefined {
	if (!(element instanceof SessionsTreeItem)) {
		return undefined;
	}

	return {
		source: element.card.kind,
		sessionId: element.card.sessionId,
		checkpointIds: [...element.card.checkpointIds],
		promptPreview: element.card.promptPreview,
		status: element.card.status,
